def login():
    """Handle user login with PIN verification"""
    global logged_in
    attempts = 3
    
    print("\\n🔐 LOGIN SCREEN")
    print("-" * 30)
    
    while attempts > 0:
        entered_pin = input("Enter your 4-digit PIN: ")
        
        if entered_pin == pin:
            logged_in = True
            print("✅ Login successful! Welcome back.")
            return True
        else:
            attempts -= 1
            if attempts > 0:
                print(f"❌ Incorrect PIN. {attempts} attempts remaining.")
            else:
                print("🚫 Account locked. Please contact customer service.")
                return False
    
    return False
