from datetime import datetime

def filter_by_date():
    """Filter transactions by date range"""
    print("\\n📅 FILTER BY DATE RANGE")
    print("-" * 40)
    
    try:
        start_date = input("Start date (YYYY-MM-DD): ")
        end_date = input("End date (YYYY-MM-DD): ")
        
        # Convert to datetime objects
        start = datetime.strptime(start_date, "%Y-%m-%d")
        end = datetime.strptime(end_date, "%Y-%m-%d")
        
        filtered = []
        for t in transaction_history:
            trans_date = datetime.strptime(t['date'].split()[0], "%Y-%m-%d")
            if start <= trans_date <= end:
                filtered.append(t)
        
        if filtered:
            print(f"\\nFound {len(filtered)} transactions:")
            for t in filtered:
                print(f"  {t['date']} - {t['type']}: \\\${t['amount']:.2f}")
        else:
            print("No transactions found in that date range.")
            
    except ValueError:
        print("Invalid date format. Use YYYY-MM-DD")
