def professional_calculator():
    """Complete error handling with all clauses"""
    
    try:
        # Code that might raise exceptions
        num1 = float(input("Enter first number: "))
        num2 = float(input("Enter second number: "))
        
        # This might raise ZeroDivisionError
        result = num1 / num2
    
    except ValueError as ve:
        # Handle wrong input type
        print(f"❌ Input error: {ve}")
        print("💡 Please enter valid numbers (e.g., 5, 3.14, -2)")
        result = None
    
    except ZeroDivisionError:
        # Handle division by zero
        print("⚠️  Division by zero is not allowed in mathematics.")
        print("💡 Try entering a non-zero second number.")
        result = None
    
    except Exception as e:
        # Catch-all for unexpected errors
        print(f"🚨 Unexpected error: {type(e).__name__}")
        print(f"🔧 Details: {e}")
        result = None
    
    else:
        # Runs ONLY if no exceptions occurred
        print("✅ Calculation successful!")
    
    finally:
        # Runs ALWAYS, regardless of exceptions
        print("📊 Calculator session ended.")
        print("-" * 40)
    
    return result
