import logging.handlers
from pathlib import Path

def setup_basic_logging():
    """Basic logging setup - good for development"""
    
    logging.basicConfig(
        level=logging.DEBUG,  # Show all messages
        format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',
