                <td style="padding: 8px; border-bottom: 1px solid #ccc;">Resource not found</td>
                <td style="padding: 8px; border-bottom: 1px solid #ccc;">✓ <code>FileNotFoundError</code></td>
                <td style="padding: 8px; border-bottom: 1px solid #ccc;">✓ <code>UserNotFoundError</code></td>
            </tr>
