    <h3>Step 2: Frames - Organizing Your Interface</h3>
    
    <b>Understanding Frames</b>
    <div style="background-color: #e0e0e0; padding: 15px; margin: 10px 0; border-radius: 5px;">
        <pre>
import tkinter as tk
from tkinter import ttk

class BankingApp:
    def __init__(self, root):
        self.root = root
        self.root.title("Python Bank")
        self.root.geometry("800x600")
        
        # Create frames for different sections
        self.create_frames()
        self.create_widgets()
    
    def create_frames(self):
        """Create organized sections using frames"""
        
        # Header Frame (top section)
        self.header_frame = ttk.Frame(self.root, relief='solid', padding=10)
        self.header_frame.pack(fill='x', padx=10, pady=(10, 5))
        
        # Main Content Frame (middle section)
        self.content_frame = ttk.Frame(self.root, relief='solid', padding=10)
        self.content_frame.pack(fill='both', expand=True, padx=10, pady=5)
        
        # Footer Frame (bottom section)
        self.footer_frame = ttk.Frame(self.root, relief='solid', padding=10)
        self.footer_frame.pack(fill='x', padx=10, pady=(5, 10))
        
        # Left Sidebar Frame
        self.sidebar_frame = ttk.Frame(self.content_frame, relief='solid', 
                                       padding=10, width=200)
        self.sidebar_frame.pack(side='left', fill='y', padx=(0, 10))
        
        # Main Display Frame
        self.display_frame = ttk.Frame(self.content_frame, relief='solid', 
                                       padding=10)
        self.display_frame.pack(side='left', fill='both', expand=True)
    
    def create_widgets(self):
        """Add widgets to frames"""
        # Header widgets
        ttk.Label(self.header_frame, text="🏦 PYTHON BANK", 
                 font=('Arial', 20, 'bold')).pack()
        
        # Sidebar widgets
        ttk.Label(self.sidebar_frame, text="Navigation", 
                 font=('Arial', 12, 'bold')).pack(pady=(0, 10))
        
        # Display area widgets
        ttk.Label(self.display_frame, text="Welcome to Python Bank!", 
                 font=('Arial', 16)).pack(pady=20)
        
        # Footer widgets
        ttk.Label(self.footer_frame, text="© 2024 Python Bank. All rights reserved.",
                 font=('Arial', 8)).pack()

if __name__ == "__main__":
    root = tk.Tk()
    app = BankingApp(root)
    root.mainloop()
        </pre>
