    <b>Frame Packing Options</b>
    <div style="background-color: #f0f8ff; padding: 15px; margin: 10px 0; border-radius: 5px;">
        <pre>
# Pack Geometry Manager Options
frame.pack()                        # Default (top, minimal size)
frame.pack(side='left')             # Left side
frame.pack(side='right')            # Right side  
frame.pack(side='top')              # Top (default)
frame.pack(side='bottom')           # Bottom
frame.pack(fill='x')                # Fill horizontally
frame.pack(fill='y')                # Fill vertically
frame.pack(fill='both')             # Fill both directions
frame.pack(expand=True)             # Expand to fill space
frame.pack(padx=10)                 # Horizontal padding
frame.pack(pady=10)                 # Vertical padding
frame.pack(ipadx=10)                # Internal horizontal padding
frame.pack(ipady=10)                # Internal vertical padding
frame.pack(anchor='n')              # Anchor: n, s, e, w, ne, nw, se, sw, center

# Example combinations:
frame.pack(side='left', fill='y')               # Sidebar
frame.pack(side='top', fill='x', padx=10)       # Header
frame.pack(fill='both', expand=True, padx=10, pady=10)  # Main content
