    <h3>Step 3: Labels - Displaying Text and Images</h3>
    
    <b>Creating and Configuring Labels</b>
    <div style="background-color: #e0e0e0; padding: 15px; margin: 10px 0; border-radius: 5px;">
        <pre>
import tkinter as tk
from tkinter import ttk
from PIL import Image, ImageTk  # For images

class LabelDemo:
    def __init__(self, root):
        self.root = root
        self.root.title("Label Demonstration")
        self.root.geometry("600x400")
        
        # Create main frame
        main_frame = ttk.Frame(self.root, padding=20)
        main_frame.pack(fill='both', expand=True)
        
        # Demo different label types
        self.create_basic_labels(main_frame)
        self.create_styled_labels(main_frame)
        self.create_image_labels(main_frame)
    
    def create_basic_labels(self, parent):
        """Create basic text labels"""
        frame = ttk.LabelFrame(parent, text="Basic Labels", padding=10)
        frame.pack(fill='x', pady=(0, 10))
        
        # Simple label
        label1 = ttk.Label(frame, text="This is a simple label")
        label1.pack(anchor='w', pady=2)
        
        # Multi-line label
        label2 = ttk.Label(frame, 
                          text="This is a multi-line label\nwith two lines of text",
                          justify='left')
        label2.pack(anchor='w', pady=2)
        
        # Label with long text and wrapping
        long_text = "This is a very long label that will wrap to multiple lines "
        long_text += "because it's too long to fit on one line."
        label3 = ttk.Label(frame, text=long_text, wraplength=300)
        label3.pack(anchor='w', pady=2)
    
    def create_styled_labels(self, parent):
        """Create labels with different styles"""
        frame = ttk.LabelFrame(parent, text="Styled Labels", padding=10)
        frame.pack(fill='x', pady=(0, 10))
        
        # Different fonts
        fonts = [
            ('Arial', 12, 'normal'),
            ('Arial', 14, 'bold'),
            ('Courier New', 12, 'italic'),
            ('Times New Roman', 16, 'bold italic')
        ]
        
        for font_spec in fonts:
            label = ttk.Label(frame, 
                            text=f"Font: {font_spec}",
                            font=font_spec)
            label.pack(anchor='w', pady=2)
        
        # Colors (using tk.Label for background/foreground)
        colors_frame = ttk.Frame(frame)
        colors_frame.pack(fill='x', pady=10)
        
        color_pairs = [
            ('black', 'white'),
            ('white', 'blue'),
            ('yellow', 'red'),
            ('lightgreen', 'darkgreen')
        ]
        
        for fg, bg in color_pairs:
            label = tk.Label(colors_frame, 
                           text=f"Foreground: {fg}, Background: {bg}",
                           fg=fg, bg=bg,
                           padx=10, pady=5)
            label.pack(side='left', padx=5)
    
    def create_image_labels(self, parent):
        """Create labels with images"""
        frame = ttk.LabelFrame(parent, text="Image Labels", padding=10)
        frame.pack(fill='x')
        
        try:
            # Create a simple image using PIL (or use a file)
            from PIL import Image, ImageDraw, ImageFont
            
            # Create a simple colored image
            img = Image.new('RGB', (100, 50), color='lightblue')
            draw = ImageDraw.Draw(img)
            draw.text((10, 15), "Bank Logo", fill='darkblue')
            
            # Convert to PhotoImage for tkinter
            self.photo = ImageTk.PhotoImage(img)
            
            # Create label with image
            img_label = ttk.Label(frame, image=self.photo)
            img_label.pack(pady=5)
            
            # Label with both image and text
            combined_label = ttk.Label(frame, 
                                      text="Python Bank",
                                      image=self.photo,
                                      compound='top')  # top, bottom, left, right
            combined_label.pack(pady=5)
            
        except ImportError:
            ttk.Label(frame, text="PIL not installed for image demo").pack()

if __name__ == "__main__":
    root = tk.Tk()
    app = LabelDemo(root)
    root.mainloop()
        </pre>
