    <h3>Step 4: Building a Banking Login Screen</h3>
    
    <b>Complete Banking Login Interface</b>
    <div style="background-color: #e0e0e0; padding: 15px; margin: 10px 0; border-radius: 5px;">
        <pre>
import tkinter as tk
from tkinter import ttk, messagebox
import hashlib

class BankingLogin:
    def __init__(self, root):
        self.root = root
        self.root.title("Python Bank - Login")
        self.root.geometry("500x400")
        self.root.resizable(False, False)
        
        # Center the window
        self.center_window(500, 400)
        
        # Configure styles
        self.configure_styles()
        
        # Create interface
        self.create_widgets()
        
        # Simulated user database (in real app, use proper database)
        self.users = {
            'john_doe': self.hash_password('1234'),
            'jane_smith': self.hash_password('5678'),
            'admin': self.hash_password('admin123')
        }
    
    def center_window(self, width, height):
        """Center the window on screen"""
        screen_width = self.root.winfo_screenwidth()
        screen_height = self.root.winfo_screenheight()
        
        x = (screen_width - width) // 2
        y = (screen_height - height) // 2
        
        self.root.geometry(f"{width}x{height}+{x}+{y}")
    
    def configure_styles(self):
        """Configure ttk styles for better appearance"""
        style = ttk.Style()
        
        # Configure colors
        style.configure('Title.TLabel', 
                       font=('Arial', 24, 'bold'),
                       foreground='darkblue')
        
        style.configure('Subtitle.TLabel',
                       font=('Arial', 10),
                       foreground='gray')
        
        style.configure('Success.TLabel',
                       font=('Arial', 10),
                       foreground='green')
        
        style.configure('Error.TLabel',
                       font=('Arial', 10),
                       foreground='red')
        
        style.configure('BankButton.TButton',
                       font=('Arial', 10, 'bold'),
                       padding=10)
    
    def create_widgets(self):
        """Create all widgets for the login screen"""
        
        # Main container frame
        main_frame = ttk.Frame(self.root, padding=30)
        main_frame.pack(fill='both', expand=True)
        
        # ========== HEADER SECTION ==========
        header_frame = ttk.Frame(main_frame)
        header_frame.pack(fill='x', pady=(0, 30))
        
        # Bank logo/icon
        logo_label = ttk.Label(header_frame, 
                              text="🏦",
                              font=('Arial', 40))
        logo_label.pack()
        
        # Bank title
        title_label = ttk.Label(header_frame,
                               text="PYTHON BANK",
                               style='Title.TLabel')
        title_label.pack(pady=(10, 5))
        
        # Subtitle
        subtitle_label = ttk.Label(header_frame,
                                  text="Secure Online Banking",
                                  style='Subtitle.TLabel')
        subtitle_label.pack()
        
        # ========== LOGIN FORM SECTION ==========
        form_frame = ttk.LabelFrame(main_frame, 
                                   text="Login to Your Account",
                                   padding=20)
        form_frame.pack(fill='x', pady=(0, 20))
        
        # Username field
        ttk.Label(form_frame, text="Username:", 
                 font=('Arial', 10)).grid(row=0, column=0, 
                                         sticky='w', pady=(0, 5))
        
        self.username_var = tk.StringVar()
        username_entry = ttk.Entry(form_frame, 
                                  textvariable=self.username_var,
                                  width=30,
                                  font=('Arial', 10))
        username_entry.grid(row=0, column=1, pady=(0, 15), padx=(10, 0))
        username_entry.focus()  # Focus on username field
        
        # Password field
        ttk.Label(form_frame, text="PIN:", 
                 font=('Arial', 10)).grid(row=1, column=0, 
                                         sticky='w', pady=(0, 5))
        
        self.password_var = tk.StringVar()
        password_entry = ttk.Entry(form_frame, 
                                  textvariable=self.password_var,
                                  show='•',  # Show dots instead of characters
                                  width=30,
                                  font=('Arial', 10))
        password_entry.grid(row=1, column=1, pady=(0, 20), padx=(10, 0))
        
        # Bind Enter key to login
        password_entry.bind('<Return>', lambda e: self.login())
        
        # Login button
        login_button = ttk.Button(form_frame,
                                 text="LOGIN",
                                 style='BankButton.TButton',
                                 command=self.login)
        login_button.grid(row=2, column=0, columnspan=2, pady=(10, 0))
        
        # ========== FOOTER SECTION ==========
        footer_frame = ttk.Frame(main_frame)
        footer_frame.pack(fill='x')
        
        # Demo credentials
        demo_frame = ttk.LabelFrame(footer_frame, 
                                   text="Demo Credentials",
                                   padding=10)
        demo_frame.pack(fill='x')
        
        credentials = [
            "Username: john_doe, PIN: 1234",
            "Username: jane_smith, PIN: 5678",
            "Username: admin, PIN: admin123"
        ]
        
        for i, cred in enumerate(credentials):
            ttk.Label(demo_frame, 
                     text=cred,
                     font=('Arial', 8)).pack(anchor='w', pady=2)
        
        # Status label (hidden initially)
        self.status_label = ttk.Label(main_frame, 
                                     text="",
                                     font=('Arial', 9))
        self.status_label.pack(pady=(10, 0))
    
    def hash_password(self, password):
        """Hash password for security"""
        return hashlib.sha256(password.encode()).hexdigest()
    
    def login(self):
        """Handle login attempt"""
        username = self.username_var.get().strip()
        password = self.password_var.get().strip()
        
        # Clear previous status
        self.status_label.config(text="", style='TLabel')
        
        # Validate inputs
        if not username or not password:
            self.show_error("Please enter both username and PIN")
            return
        
        # Check credentials
        if username in self.users:
            hashed_input = self.hash_password(password)
            if self.users[username] == hashed_input:
                self.show_success(f"Welcome, {username}!")
                
                # Simulate loading
                self.status_label.config(text="Redirecting to dashboard...")
                self.root.after(1500, self.open_dashboard)
            else:
                self.show_error("Incorrect PIN. Please try again.")
        else:
            self.show_error("Username not found.")
    
    def show_error(self, message):
        """Display error message"""
        self.status_label.config(text=message, style='Error.TLabel')
        
        # Shake animation for error
        self.shake_window()
    
    def show_success(self, message):
        """Display success message"""
        self.status_label.config(text=message, style='Success.TLabel')
    
    def shake_window(self):
        """Create a shake effect for wrong login"""
        x = self.root.winfo_x()
        y = self.root.winfo_y()
        
        for i in range(5):
            # Move right
            self.root.geometry(f"+{x+5}+{y}")
            self.root.update()
            self.root.after(30)
            
            # Move left
            self.root.geometry(f"+{x-5}+{y}")
            self.root.update()
            self.root.after(30)
        
        # Return to original position
        self.root.geometry(f"+{x}+{y}")
    
    def open_dashboard(self):
        """Open banking dashboard (simulated)"""
        messagebox.showinfo("Login Successful", 
                           "Welcome to Python Bank Dashboard!\n\n"
                           "In the next lessons, we'll build:\n"
                           "• Account overview\n"
                           "• Transaction history\n"
                           "• Money transfer\n"
                           "• And more!")
        
        # In a real app, you would open the main banking window
        # For now, just close the login window
        self.root.destroy()

if __name__ == "__main__":
    root = tk.Tk()
    app = BankingLogin(root)
    
    # Set window icon (if you have an icon file)
    try:
        root.iconbitmap('bank_icon.ico')  # Windows .ico file
    except:
        pass  # Skip if icon file not found
    
    root.mainloop()
        </pre>
