    <h3>Step 1: Creating Basic Buttons</h3>
    
    <b>Button Creation Examples</b>
    <div style="background-color: #e0e0e0; padding: 15px; margin: 10px 0; border-radius: 5px;">
        <pre>
import tkinter as tk
from tkinter import ttk

class ButtonBasics:
    def __init__(self, root):
        self.root = root
        self.root.title("Button Basics")
        self.root.geometry("500x400")
        
        main_frame = ttk.Frame(self.root, padding=20)
        main_frame.pack(fill='both', expand=True)
        
        self.create_basic_buttons(main_frame)
        self.create_special_buttons(main_frame)
        self.create_state_demo(main_frame)
    
    def create_basic_buttons(self, parent):
        """Create basic button examples"""
        frame = ttk.LabelFrame(parent, text="Basic Buttons", padding=10)
        frame.pack(fill='x', pady=(0, 10))
        
        # Simple button with command
        simple_btn = ttk.Button(frame, text="Click Me!", 
                               command=self.simple_click)
        simple_btn.pack(pady=5)
        
        # Button with parameters
        styled_btn = ttk.Button(frame, 
                               text="Styled Button",
                               width=20,
                               command=lambda: self.button_click("Styled"))
        styled_btn.pack(pady=5)
        
        # Button with keyboard shortcut (Alt+S)
        shortcut_btn = ttk.Button(frame,
                                 text="Shortcut (Alt+S)",
                                 command=self.shortcut_action)
        shortcut_btn.pack(pady=5)
        self.root.bind('<Alt-s>', lambda e: self.shortcut_action())
        
        # Disabled button
        self.disabled_btn = ttk.Button(frame,
                                      text="Disabled Button",
                                      state='disabled',
                                      command=self.disabled_click)
        self.disabled_btn.pack(pady=5)
        
        # Enable/disable toggle button
        toggle_btn = ttk.Button(frame,
                               text="Enable/Disable Toggle",
                               command=self.toggle_button_state)
        toggle_btn.pack(pady=5)
    
    def create_special_buttons(self, parent):
        """Create checkbuttons and radiobuttons"""
        frame = ttk.LabelFrame(parent, text="Special Buttons", padding=10)
        frame.pack(fill='x', pady=(0, 10))
        
        # Checkbutton with variable
        self.check_var = tk.BooleanVar(value=False)
        check_btn = ttk.Checkbutton(frame,
                                   text="Accept Terms & Conditions",
                                   variable=self.check_var,
                                   command=self.checkbox_changed)
        check_btn.pack(anchor='w', pady=5)
        
        # Radiobuttons for account type
        self.account_type = tk.StringVar(value="checking")
        
        radio_frame = ttk.Frame(frame)
        radio_frame.pack(anchor='w', pady=5)
        
        ttk.Label(radio_frame, text="Account Type:").pack(side='left', padx=(0, 10))
        
        ttk.Radiobutton(radio_frame,
                       text="Checking",
                       variable=self.account_type,
                       value="checking",
                       command=self.radio_changed).pack(side='left', padx=5)
        
        ttk.Radiobutton(radio_frame,
                       text="Savings",
                       variable=self.account_type,
                       value="savings",
                       command=self.radio_changed).pack(side='left', padx=5)
        
        ttk.Radiobutton(radio_frame,
                       text="Business",
                       variable=self.account_type,
                       value="business",
                       command=self.radio_changed).pack(side='left', padx=5)
    
    def create_state_demo(self, parent):
        """Demo button states and feedback"""
        frame = ttk.LabelFrame(parent, text="Button States & Feedback", padding=10)
        frame.pack(fill='x')
        
        # Status label
        self.status_label = ttk.Label(frame, text="Ready", font=('Arial', 10))
        self.status_label.pack(pady=(0, 10))
        
        # Button grid with different states
        btn_frame = ttk.Frame(frame)
        btn_frame.pack()
        
        states = ['normal', 'active', 'disabled']
        for i, state in enumerate(states):
            btn = ttk.Button(btn_frame,
                            text=f"State: {state}",
                            state=state,
                            command=lambda s=state: self.show_state(s))
            btn.grid(row=0, column=i, padx=5)
        
        # Progress simulation button
        self.simulate_btn = ttk.Button(frame,
                                      text="Simulate Transaction",
                                      command=self.simulate_transaction)
        self.simulate_btn.pack(pady=10)
        
        # Progress label
        self.progress_label = ttk.Label(frame, text="")
        self.progress_label.pack()
    
    # ========== EVENT HANDLERS ==========
    
    def simple_click(self):
        """Handle simple button click"""
        print("Simple button clicked!")
        self.status_label.config(text="Simple button clicked!")
    
    def button_click(self, button_name):
        """Handle button click with parameter"""
        message = f"{button_name} button clicked!"
        print(message)
        self.status_label.config(text=message)
    
    def shortcut_action(self):
        """Handle keyboard shortcut"""
        print("Shortcut activated!")
        self.status_label.config(text="Keyboard shortcut activated!")
    
    def disabled_click(self):
        """This shouldn't be called when disabled"""
        print("Disabled button clicked (shouldn't happen)")
    
    def toggle_button_state(self):
        """Toggle disabled button state"""
        current_state = self.disabled_btn['state']
        new_state = 'normal' if current_state == 'disabled' else 'disabled'
        self.disabled_btn.config(state=new_state)
        
        state_text = "enabled" if new_state == 'normal' else "disabled"
        self.status_label.config(text=f"Button {state_text}")
    
    def checkbox_changed(self):
        """Handle checkbox state change"""
        checked = self.check_var.get()
        status = "accepted" if checked else "not accepted"
        print(f"Terms {status}")
        self.status_label.config(text=f"Terms {status}")
    
    def radio_changed(self):
        """Handle radiobutton selection"""
        selected = self.account_type.get()
        print(f"Selected account type: {selected}")
        self.status_label.config(text=f"Account type: {selected}")
    
    def show_state(self, state):
        """Show button state"""
        self.status_label.config(text=f"Button in '{state}' state")
    
    def simulate_transaction(self):
        """Simulate a transaction with button state changes"""
        # Disable button during transaction
        self.simulate_btn.config(state='disabled')
        self.status_label.config(text="Processing transaction...")
        
        # Simulate steps
        steps = [
            "Validating...",
            "Checking balance...",
            "Processing...",
            "Completing..."
        ]
        
        def process_step(step_index=0):
            if step_index < len(steps):
                step = steps[step_index]
                self.progress_label.config(text=step)
                print(step)
                
                # Schedule next step
                self.root.after(1000, lambda: process_step(step_index + 1))
            else:
                # Transaction complete
                self.progress_label.config(text="Transaction complete!")
                self.status_label.config(text="Transaction successful!")
                self.simulate_btn.config(state='normal')
        
        # Start processing
        process_step()

if __name__ == "__main__":
    root = tk.Tk()
    app = ButtonBasics(root)
    root.mainloop()
        </pre>
    </div>

    <h3>Step 2: Banking Transaction Buttons</h3>
    
    <b>Interactive Banking Interface</b>
    <div style="background-color: #f0f8ff; padding: 15px; margin: 10px 0; border-radius: 5px;">
        <pre>
import tkinter as tk
from tkinter import ttk, messagebox

class BankingTransactions:
    def __init__(self, root):
        self.root = root
        self.root.title("Python Bank - Transactions")
        self.root.geometry("700x600")
        
        # Bank account simulation
        self.balance = 2500.00
        self.transaction_history = []
        
        self.setup_styles()
        self.create_widgets()
    
    def setup_styles(self):
        """Configure button styles"""
        style = ttk.Style()
        
        # Primary action button (green)
        style.configure('Primary.TButton',
                       font=('Arial', 10, 'bold'),
                       padding=10,
                       foreground='white')
        
        # Danger action button (red)
        style.configure('Danger.TButton',
                       font=('Arial', 10, 'bold'),
                       padding=10,
                       foreground='white')
        
        # Success button (green)
        style.configure('Success.TButton',
                       font=('Arial', 10, 'bold'),
                       padding=10)
        
        # Small action button
        style.configure('Small.TButton',
                       font=('Arial', 9),
                       padding=5)
    
    def create_widgets(self):
        """Create banking transaction interface"""
        main_frame = ttk.Frame(self.root, padding=20)
        main_frame.pack(fill='both', expand=True)
        
        # Header
        self.create_header(main_frame)
        
        # Account Overview
        self.create_account_overview(main_frame)
        
        # Quick Actions
        self.create_quick_actions(main_frame)
        
        # Transaction Form
        self.create_transaction_form(main_frame)
        
        # Transaction History
        self.create_transaction_history(main_frame)
        
        # Footer
        self.create_footer(main_frame)
    
    def create_header(self, parent):
        """Create application header"""
        header_frame = ttk.Frame(parent)
        header_frame.pack(fill='x', pady=(0, 20))
        
        # Bank logo and title
        ttk.Label(header_frame,
                 text="🏦",
                 font=('Arial', 30)).pack(side='left')
        
        ttk.Label(header_frame,
                 text="PYTHON BANK",
                 font=('Arial', 20, 'bold'),
                 foreground='darkblue').pack(side='left', padx=10)
        
        # Current time display
        self.time_label = ttk.Label(header_frame,
                                   font=('Arial', 10),
                                   foreground='gray')
        self.time_label.pack(side='right')
        self.update_time()
    
    def create_account_overview(self, parent):
        """Create account overview section"""
        frame = ttk.LabelFrame(parent, text="Account Overview", padding=15)
        frame.pack(fill='x', pady=(0, 20))
        
        # Account info
        info_frame = ttk.Frame(frame)
        info_frame.pack(fill='x', pady=(0, 15))
        
        ttk.Label(info_frame,
                 text="Account:",
                 font=('Arial', 10)).pack(side='left')
        
        ttk.Label(info_frame,
                 text="CHECKING ••••1234",
                 font=('Arial', 10, 'bold')).pack(side='left', padx=5)
        
        # Balance display
        balance_frame = ttk.Frame(frame)
        balance_frame.pack(fill='x')
        
        ttk.Label(balance_frame,
                 text="Current Balance:",
                 font=('Arial', 12)).pack(side='left')
        
        self.balance_label = ttk.Label(balance_frame,
                                      text=f"\\\${self.balance:,.2f}",
                                      font=('Arial', 24, 'bold'),
                                      foreground='darkgreen')
        self.balance_label.pack(side='left', padx=10)
        
        # Refresh button
        ttk.Button(balance_frame,
                  text="🔄 Refresh",
                  style='Small.TButton',
                  command=self.refresh_balance).pack(side='right')
    
    def create_quick_actions(self, parent):
        """Create quick action buttons"""
        frame = ttk.LabelFrame(parent, text="Quick Actions", padding=15)
        frame.pack(fill='x', pady=(0, 20))
        
        # Create button grid
        actions = [
            ("💳 Deposit", self.show_deposit_form, 'Primary.TButton'),
            ("🏧 Withdraw", self.show_withdraw_form, 'Danger.TButton'),
            ("🔄 Transfer", self.show_transfer_form, 'Primary.TButton'),
            ("📜 Statement", self.show_statement, 'Small.TButton'),
            ("🔐 Security", self.show_security, 'Small.TButton'),
            ("⚙️ Settings", self.show_settings, 'Small.TButton')
        ]
        
        # Arrange buttons in grid
        for i, (text, command, style) in enumerate(actions):
            row = i // 3
            col = i % 3
            
            btn = ttk.Button(frame,
                           text=text,
                           style=style,
                           command=command)
            btn.grid(row=row, column=col, padx=5, pady=5, sticky='ew')
        
        # Configure grid columns to expand
        for i in range(3):
            frame.grid_columnconfigure(i, weight=1)
    
    def create_transaction_form(self, parent):
        """Create transaction input form"""
        self.form_frame = ttk.LabelFrame(parent, text="New Transaction", padding=15)
        self.form_frame.pack(fill='x', pady=(0, 20))
        
        # Initially hide the form
        self.form_frame.pack_forget()
        
        # Form will be populated by specific transaction type
        self.form_content = None
    
    def create_transaction_history(self, parent):
        """Create transaction history display"""
        frame = ttk.LabelFrame(parent, text="Recent Transactions", padding=15)
        frame.pack(fill='both', expand=True)
        
        # Create Treeview for transaction history
        columns = ('date', 'description', 'amount', 'balance')
        self.history_tree = ttk.Treeview(frame, columns=columns, show='headings', height=8)
        
        # Define headings
        self.history_tree.heading('date', text='Date')
        self.history_tree.heading('description', text='Description')
        self.history_tree.heading('amount', text='Amount')
        self.history_tree.heading('balance', text='Balance')
        
        # Define columns
        self.history_tree.column('date', width=100)
        self.history_tree.column('description', width=200)
        self.history_tree.column('amount', width=100)
        self.history_tree.column('balance', width=100)
        
        # Add scrollbar
        scrollbar = ttk.Scrollbar(frame, orient='vertical', command=self.history_tree.yview)
        self.history_tree.configure(yscrollcommand=scrollbar.set)
        
        # Pack tree and scrollbar
        self.history_tree.pack(side='left', fill='both', expand=True)
        scrollbar.pack(side='right', fill='y')
        
        # Load sample transactions
        self.load_sample_transactions()
    
    def create_footer(self, parent):
        """Create application footer"""
        footer_frame = ttk.Frame(parent)
        footer_frame.pack(fill='x', pady=(20, 0))
        
        ttk.Label(footer_frame,
                 text="© 2024 Python Bank • Secure Online Banking",
                 font=('Arial', 8),
                 foreground='gray').pack()
    
    def update_time(self):
        """Update current time display"""
        from datetime import datetime
        current_time = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        self.time_label.config(text=f"Last updated: {current_time}")
        self.root.after(1000, self.update_time)
    
    def refresh_balance(self):
        """Refresh balance display"""
        # In real app, this would fetch from server
        # For demo, just update the label
        self.balance_label.config(text=f"\\\${self.balance:,.2f}")
        self.update_time()
        messagebox.showinfo("Balance Refreshed", "Account balance has been updated.")
    
    def show_deposit_form(self):
        """Show deposit form"""
        self.show_transaction_form("Deposit", "primary")
    
    def show_withdraw_form(self):
        """Show withdrawal form"""
        self.show_transaction_form("Withdraw", "danger")
    
    def show_transfer_form(self):
        """Show transfer form"""
        self.show_transaction_form("Transfer", "primary")
    
    def show_transaction_form(self, transaction_type, style_type):
        """Show transaction input form"""
        # Remove previous form content
        if self.form_content:
            self.form_content.destroy()
        
        # Show form frame
        self.form_frame.pack(fill='x', pady=(0, 20))
        
        # Create new form content
        self.form_content = ttk.Frame(self.form_frame)
        self.form_content.pack(fill='x')
        
        # Title
        ttk.Label(self.form_content,
                 text=f"{transaction_type} Money",
                 font=('Arial', 14, 'bold')).pack(anchor='w', pady=(0, 15))
        
        # Amount input
        amount_frame = ttk.Frame(self.form_content)
        amount_frame.pack(fill='x', pady=(0, 10))
        
        ttk.Label(amount_frame,
                 text="Amount:",
                 width=15).pack(side='left')
        
        self.amount_var = tk.StringVar()
        amount_entry = ttk.Entry(amount_frame,
                                textvariable=self.amount_var,
                                font=('Arial', 12),
                                width=20)
        amount_entry.pack(side='left')
        amount_entry.focus()
        
        ttk.Label(amount_frame,
                 text="USD",
                 font=('Arial', 10)).pack(side='left', padx=5)
        
        # Description input (for deposit/withdraw)
        if transaction_type in ["Deposit", "Withdraw"]:
            desc_frame = ttk.Frame(self.form_content)
            desc_frame.pack(fill='x', pady=(0, 10))
            
            ttk.Label(desc_frame,
                     text="Description:",
                     width=15).pack(side='left')
            
            self.desc_var = tk.StringVar()
            desc_entry = ttk.Entry(desc_frame,
                                  textvariable=self.desc_var,
                                  width=30)
            desc_entry.pack(side='left')
        
        # Recipient input (for transfer)
        if transaction_type == "Transfer":
            recipient_frame = ttk.Frame(self.form_content)
            recipient_frame.pack(fill='x', pady=(0, 10))
            
            ttk.Label(recipient_frame,
                     text="To Account:",
                     width=15).pack(side='left')
            
            self.recipient_var = tk.StringVar()
            recipient_entry = ttk.Entry(recipient_frame,
                                       textvariable=self.recipient_var,
                                       width=30)
            recipient_entry.pack(side='left')
        
        # Buttons
        btn_frame = ttk.Frame(self.form_content)
        btn_frame.pack(fill='x', pady=(10, 0))
        
        # Submit button with appropriate style
        style = 'Primary.TButton' if style_type == 'primary' else 'Danger.TButton'
        submit_btn = ttk.Button(btn_frame,
                               text=f"Submit {transaction_type}",
                               style=style,
                               command=lambda: self.process_transaction(transaction_type))
        submit_btn.pack(side='left', padx=(0, 10))
        
        # Cancel button
        ttk.Button(btn_frame,
                  text="Cancel",
                  command=self.hide_form).pack(side='left')
    
    def hide_form(self):
        """Hide transaction form"""
        self.form_frame.pack_forget()
        if self.form_content:
            self.form_content.destroy()
            self.form_content = None
    
    def process_transaction(self, transaction_type):
        """Process the transaction"""
        try:
            amount = float(self.amount_var.get())
            
            if amount <= 0:
                messagebox.showerror("Invalid Amount", "Amount must be positive.")
                return
            
            if transaction_type == "Withdraw" and amount > self.balance:
                messagebox.showerror("Insufficient Funds", 
                                   f"Insufficient balance. Available: \\\${self.balance:,.2f}")
                return
            
            # Confirm transaction
            confirm = messagebox.askyesno(
                "Confirm Transaction",
                f"Confirm {transaction_type.lower()} of \\\${amount:,.2f}?"
            )
            
            if not confirm:
                return
            
            # Process transaction
            old_balance = self.balance
            
            if transaction_type == "Deposit":
                self.balance += amount
                description = self.desc_var.get() or "Deposit"
            elif transaction_type == "Withdraw":
                self.balance -= amount
                description = self.desc_var.get() or "Withdrawal"
            elif transaction_type == "Transfer":
                self.balance -= amount
                description = f"Transfer to {self.recipient_var.get()}"
            
            # Add to history
            from datetime import datetime
            transaction = {
                'date': datetime.now().strftime("%Y-%m-%d %H:%M"),
                'description': description,
                'amount': f"+\\\${amount:,.2f}" if transaction_type == "Deposit" else f"-\\\${amount:,.2f}",
                'balance': f"\\\${self.balance:,.2f}"
            }
            
            self.transaction_history.append(transaction)
            self.update_history_tree()
            
            # Update balance display
            self.balance_label.config(text=f"\\\${self.balance:,.2f}")
            
            # Hide form
            self.hide_form()
            
            # Show success message
            messagebox.showinfo(
                "Transaction Successful",
                f"{transaction_type} of \\\${amount:,.2f} completed.\n"
                f"New balance: \\\${self.balance:,.2f}"
            )
            
        except ValueError:
            messagebox.showerror("Invalid Input", "Please enter a valid amount.")
        except Exception as e:
            messagebox.showerror("Error", f"Transaction failed: {str(e)}")
    
    def load_sample_transactions(self):
        """Load sample transaction history"""
        sample_transactions = [
            ("2024-01-15 09:30", "Salary Deposit", "+$2,500.00", "$2,845.67"),
            ("2024-01-15 14:15", "Grocery Store", "-$85.50", "$2,760.17"),
            ("2024-01-14 11:20", "Online Shopping", "-$129.99", "$2,630.18"),
            ("2024-01-13 16:45", "ATM Withdrawal", "-$100.00", "$2,530.18"),
            ("2024-01-12 10:00", "Utility Bill", "-$150.00", "$2,380.18"),
            ("2024-01-11 13:30", "Transfer to Savings", "-$500.00", "$1,880.18"),
            ("2024-01-10 09:15", "Interest Earned", "+$12.50", "$1,892.68"),
            ("2024-01-09 15:45", "Coffee Shop", "-$5.75", "$1,886.93")
        ]
        
        for transaction in sample_transactions:
            self.history_tree.insert('', 'end', values=transaction)
    
    def update_history_tree(self):
        """Update transaction history display"""
        # Clear existing items
        for item in self.history_tree.get_children():
            self.history_tree.delete(item)
        
        # Add all transactions (newest first)
        for transaction in reversed(self.transaction_history[-8:]):  # Last 8 transactions
            self.history_tree.insert('', 0, values=(
                transaction['date'],
                transaction['description'],
                transaction['amount'],
                transaction['balance']
            ))
        
        # Add sample transactions if history is empty
        if not self.transaction_history:
            self.load_sample_transactions()
    
    def show_statement(self):
        """Show account statement"""
        messagebox.showinfo("Account Statement", 
                          "Statement download started.\n"
                          "In a real app, this would generate a PDF statement.")
    
    def show_security(self):
        """Show security settings"""
        messagebox.showinfo("Security Settings", 
                          "Security settings would be displayed here.")
    
    def show_settings(self):
        """Show application settings"""
        messagebox.showinfo("Settings", 
                          "Application settings would be displayed here.")

if __name__ == "__main__":
    root = tk.Tk()
    app = BankingTransactions(root)
    root.mainloop()
