    <h3>Step 3: Advanced Event Binding</h3>
    
    <b>Keyboard & Mouse Event Handling</b>
    <div style="background-color: #e0e0e0; padding: 15px; margin: 10px 0; border-radius: 5px;">
        <pre>
import tkinter as tk
from tkinter import ttk

class AdvancedEvents:
    def __init__(self, root):
        self.root = root
        self.root.title("Advanced Event Binding")
        self.root.geometry("600x500")
        
        # Track mouse position
        self.mouse_x = 0
        self.mouse_y = 0
        
        # Track key states
        self.keys_pressed = set()
        
        self.create_widgets()
        self.bind_events()
    
    def create_widgets(self):
        """Create demonstration widgets"""
        main_frame = ttk.Frame(self.root, padding=20)
        main_frame.pack(fill='both', expand=True)
        
        # Mouse tracking area
        mouse_frame = ttk.LabelFrame(main_frame, text="Mouse Events", padding=10)
        mouse_frame.pack(fill='x', pady=(0, 10))
        
        self.mouse_canvas = tk.Canvas(mouse_frame, height=150, bg='lightgray')
        self.mouse_canvas.pack(fill='x', pady=(0, 10))
        
        self.mouse_label = ttk.Label(mouse_frame, text="Move mouse over canvas...")
        self.mouse_label.pack()
        
        # Keyboard tracking area
        key_frame = ttk.LabelFrame(main_frame, text="Keyboard Events", padding=10)
        key_frame.pack(fill='x', pady=(0, 10))
        
        self.key_label = ttk.Label(key_frame, text="Press any key...")
        self.key_label.pack(pady=(0, 10))
        
        self.key_display = tk.Text(key_frame, height=5, width=50, state='disabled')
        self.key_display.pack()
        
        # Focus demonstration
        focus_frame = ttk.LabelFrame(main_frame, text="Focus Events", padding=10)
        focus_frame.pack(fill='x')
        
        ttk.Label(focus_frame, text="Tab between entries to see focus events:").pack(anchor='w')
        
        self.entry1 = ttk.Entry(focus_frame)
        self.entry1.pack(fill='x', pady=5)
        
        self.entry2 = ttk.Entry(focus_frame)
        self.entry2.pack(fill='x', pady=5)
        
        self.entry3 = ttk.Entry(focus_frame)
        self.entry3.pack(fill='x', pady=5)
        
        self.focus_label = ttk.Label(focus_frame, text="No focus event yet")
        self.focus_label.pack(pady=5)
    
    def bind_events(self):
        """Bind various events to widgets"""
        
        # ========== MOUSE EVENTS ==========
        self.mouse_canvas.bind('<Enter>', self.mouse_entered)
        self.mouse_canvas.bind('<Leave>', self.mouse_left)
        self.mouse_canvas.bind('<Motion>', self.mouse_moved)
        self.mouse_canvas.bind('<Button-1>', self.mouse_clicked)
        self.mouse_canvas.bind('<Double-Button-1>', self.mouse_double_clicked)
        self.mouse_canvas.bind('<ButtonRelease-1>', self.mouse_released)
        self.mouse_canvas.bind('<B1-Motion>', self.mouse_dragged)
        self.mouse_canvas.bind('<MouseWheel>', self.mouse_wheel)
        
        # ========== KEYBOARD EVENTS ==========
        self.root.bind('<KeyPress>', self.key_pressed)
        self.root.bind('<KeyRelease>', self.key_released)
        self.root.bind('<Control-s>', self.save_shortcut)
        self.root.bind('<Control-q>', self.quit_shortcut)
        self.root.bind('<Escape>', self.escape_pressed)
        
        # ========== FOCUS EVENTS ==========
        self.entry1.bind('<FocusIn>', lambda e: self.focus_changed("Entry 1"))
        self.entry1.bind('<FocusOut>', lambda e: self.focus_changed("Entry 1 lost focus"))
        
        self.entry2.bind('<FocusIn>', lambda e: self.focus_changed("Entry 2"))
        self.entry2.bind('<FocusOut>', lambda e: self.focus_changed("Entry 2 lost focus"))
        
        self.entry3.bind('<FocusIn>', lambda e: self.focus_changed("Entry 3"))
        self.entry3.bind('<FocusOut>', lambda e: self.focus_changed("Entry 3 lost focus"))
        
        # ========== WINDOW EVENTS ==========
        self.root.bind('<Configure>', self.window_resized)
        self.root.protocol("WM_DELETE_WINDOW", self.on_closing)
    
    # ========== MOUSE EVENT HANDLERS ==========
    
    def mouse_entered(self, event):
        """Mouse entered the canvas"""
        self.mouse_label.config(text="Mouse entered canvas")
        self.mouse_canvas.config(bg='lightblue')
    
    def mouse_left(self, event):
        """Mouse left the canvas"""
        self.mouse_label.config(text="Mouse left canvas")
        self.mouse_canvas.config(bg='lightgray')
    
    def mouse_moved(self, event):
        """Mouse moved on canvas"""
        self.mouse_x = event.x
        self.mouse_y = event.y
        self.mouse_label.config(text=f"Mouse at: ({event.x}, {event.y})")
        
        # Draw a small dot at mouse position
        self.mouse_canvas.delete("tracker")
        self.mouse_canvas.create_oval(event.x-2, event.y-2, event.x+2, event.y+2, 
                                     fill='red', tags="tracker")
    
    def mouse_clicked(self, event):
        """Mouse button clicked"""
        self.mouse_label.config(text=f"Clicked at: ({event.x}, {event.y})")
        self.mouse_canvas.create_oval(event.x-5, event.y-5, event.x+5, event.y+5, 
                                     fill='blue', tags="click")
    
    def mouse_double_clicked(self, event):
        """Mouse double clicked"""
        self.mouse_label.config(text=f"Double clicked at: ({event.x}, {event.y})")
        self.mouse_canvas.create_rectangle(event.x-10, event.y-10, event.x+10, event.y+10, 
                                          fill='green', tags="double")
    
    def mouse_released(self, event):
        """Mouse button released"""
        self.mouse_label.config(text=f"Released at: ({event.x}, {event.y})")
    
    def mouse_dragged(self, event):
        """Mouse dragged (button held while moving)"""
        self.mouse_label.config(text=f"Dragging: ({event.x}, {event.y})")
        self.mouse_canvas.create_line(self.mouse_x, self.mouse_y, event.x, event.y, 
                                     fill='purple', width=2, tags="drag")
        self.mouse_x, self.mouse_y = event.x, event.y
    
    def mouse_wheel(self, event):
        """Mouse wheel scrolled"""
        direction = "up" if event.delta > 0 else "down"
        self.mouse_label.config(text=f"Mouse wheel scrolled {direction}")
    
    # ========== KEYBOARD EVENT HANDLERS ==========
    
    def key_pressed(self, event):
        """Key pressed"""
        self.keys_pressed.add(event.keysym)
        self.update_key_display()
        
        # Special handling for modifier keys
        if event.keysym in ['Control_L', 'Control_R', 'Alt_L', 'Alt_R', 'Shift_L', 'Shift_R']:
            self.key_label.config(text=f"{event.keysym} pressed")
        else:
            self.key_label.config(text=f"Key pressed: {event.keysym} (char: {event.char})")
    
    def key_released(self, event):
        """Key released"""
        if event.keysym in self.keys_pressed:
            self.keys_pressed.remove(event.keysym)
        self.update_key_display()
    
    def update_key_display(self):
        """Update keyboard display"""
        self.key_display.config(state='normal')
        self.key_display.delete('1.0', 'end')
        
        if self.keys_pressed:
            self.key_display.insert('1.0', "Keys currently pressed:\n")
            for key in sorted(self.keys_pressed):
                self.key_display.insert('end', f"  • {key}\n")
        else:
            self.key_display.insert('1.0', "No keys pressed")
        
        self.key_display.config(state='disabled')
    
    def save_shortcut(self, event):
        """Ctrl+S shortcut"""
        self.key_label.config(text="Ctrl+S: Save shortcut activated")
        return "break"  # Prevent default behavior
    
    def quit_shortcut(self, event):
        """Ctrl+Q shortcut"""
        if messagebox.askyesno("Quit", "Are you sure you want to quit?"):
            self.root.destroy()
        return "break"
    
    def escape_pressed(self, event):
        """Escape key pressed"""
        self.key_label.config(text="Escape: Clearing all inputs")
        self.entry1.delete(0, 'end')
        self.entry2.delete(0, 'end')
        self.entry3.delete(0, 'end')
    
    # ========== FOCUS EVENT HANDLERS ==========
    
    def focus_changed(self, widget_name):
        """Focus changed between widgets"""
        self.focus_label.config(text=f"Focus: {widget_name}")
    
    # ========== WINDOW EVENT HANDLERS ==========
    
    def window_resized(self, event):
        """Window resized"""
        if event.widget == self.root:
            self.key_label.config(text=f"Window size: {event.width}x{event.height}")
    
    def on_closing(self):
        """Window closing event"""
        if messagebox.askyesno("Quit", "Do you want to quit?"):
            print("Application closing...")
            self.root.destroy()

if __name__ == "__main__":
    root = tk.Tk()
    app = AdvancedEvents(root)
    root.mainloop()
        </pre>
    </div>

    <h3>Event Binding Reference</h3>
    <div style="background-color: #fff0e6; padding: 15px; margin: 10px 0; border-radius: 5px; font-family: monospace;">
        <b>Common Event Patterns:</b><br/>
        <br/>
        <b>Mouse Events:</b><br/>
        <Button-1>        - Left mouse button click<br/>
        <Button-2>        - Middle mouse button click<br/>
        <Button-3>        - Right mouse button click<br/>
        <Double-Button-1> - Left mouse button double click<br/>
        <B1-Motion>       - Mouse drag with left button<br/>
        <Motion>          - Mouse movement<br/>
        <Enter>           - Mouse enters widget<br/>
        <Leave>           - Mouse leaves widget<br/>
        <MouseWheel>      - Mouse wheel scroll<br/>
        <br/>
        <b>Keyboard Events:</b><br/>
        <KeyPress>        - Any key pressed<br/>
        <KeyRelease>      - Any key released<br/>
        <KeyPress-a>      - Specific key 'a' pressed<br/>
        <Return>          - Enter/Return key<br/>
        <Escape>          - Escape key<br/>
        <Tab>             - Tab key<br/>
        <Shift_L>         - Left Shift key<br/>
        <Control_L>       - Left Control key<br/>
        <Alt_L>           - Left Alt key<br/>
        <F1>              - Function key F1<br/>
        <br/>
        <b>Focus Events:</b><br/>
        <FocusIn>         - Widget gains focus<br/>
        <FocusOut>        - Widget loses focus<br/>
        <br/>
        <b>Window Events:</b><br/>
        <Configure>       - Window resized or moved<br/>
        <Map>             - Window mapped (shown)<br/>
        <Unmap>           - Window unmapped (hidden)<br/>
        <Destroy>         - Window destroyed<br/>
        <br/>
        <b>Event Object Properties:</b><br/>
        event.x, event.y  - Mouse coordinates<br/>
        event.x_root, event.y_root - Screen coordinates<br/>
        event.char        - Character for keyboard events<br/>
        event.keysym      - Key symbol name<br/>
        event.keycode     - Key code number<br/>
        event.state       - Modifier keys state<br/>
        event.widget      - Widget that received event<br/>
        event.type        - Event type<br/>
        <br/>
        <b>Modifier Keys in event.state:</b><br/>
        0x0001 - Shift<br/>
        0x0002 - Caps Lock<br/>
        0x0004 - Control<br/>
        0x0008 - Left Alt<br/>
        0x0010 - Num Lock<br/>
        0x0080 - Right Alt<br/>
    </div>

    <h3>Hands-On Exercise: Create a Banking Calculator</h3>
    
    <b>Task:</b> Build a financial calculator with interactive buttons
    <div style="background-color: #f0f8ff; padding: 15px; margin: 10px 0; border-radius: 5px;">
        <pre>
class BankingCalculator:
    """
    Create a financial calculator with:
    1. Number pad (0-9, decimal point)
    2. Basic operations (+, -, ×, ÷)
    3. Financial functions (interest, loan payment, etc.)
    4. Memory functions (M+, M-, MR, MC)
    5. Clear and backspace buttons
    6. Display area with calculation history
    """
    
    def __init__(self, root):
        self.root = root
        self.root.title("Banking Calculator")
        self.root.geometry("400x500")
        
        # Calculator state
        self.current_input = "0"
        self.previous_value = None
        self.operation = None
        self.memory = 0
        self.history = []
        
        self.create_widgets()
        self.bind_events()
    
    def create_widgets(self):
        """Create calculator interface"""
        main_frame = ttk.Frame(self.root, padding=10)
        main_frame.pack(fill='both', expand=True)
        
        # Display area
        self.create_display(main_frame)
        
        # Memory buttons row
        self.create_memory_buttons(main_frame)
        
        # Calculator buttons
        self.create_calculator_buttons(main_frame)
        
        # Financial functions
        self.create_financial_functions(main_frame)
    
    def create_display(self, parent):
        """Create calculator display"""
        display_frame = ttk.Frame(parent)
        display_frame.pack(fill='x', pady=(0, 10))
        
        # History label (small, shows previous calculation)
        self.history_label = ttk.Label(display_frame, 
                                      text="",
                                      font=('Arial', 8),
                                      foreground='gray',
                                      anchor='e')
        self.history_label.pack(fill='x')
        
        # Main display
        self.display_var = tk.StringVar(value="0")
        display = ttk.Entry(display_frame,
                           textvariable=self.display_var,
                           font=('Arial', 20, 'bold'),
                           justify='right',
                           state='readonly')
        display.pack(fill='x', ipady=10)
    
    def create_memory_buttons(self, parent):
        """Create memory function buttons"""
        mem_frame = ttk.Frame(parent)
        mem_frame.pack(fill='x', pady=(0, 5))
        
        memory_buttons = [
            ("MC", self.memory_clear, 'Small.TButton'),
            ("MR", self.memory_recall, 'Small.TButton'),
            ("M+", self.memory_add, 'Small.TButton'),
            ("M-", self.memory_subtract, 'Small.TButton'),
            ("MS", self.memory_store, 'Small.TButton')
        ]
        
        for text, command, style in memory_buttons:
            btn = ttk.Button(mem_frame,
                           text=text,
                           style=style,
                           command=command,
                           width=6)
            btn.pack(side='left', padx=2)
    
    def create_calculator_buttons(self, parent):
        """Create calculator number pad and operations"""
        # Button configuration
        buttons = [
            # Row 1
            [("C", self.clear, 'Danger.TButton'),
             ("CE", self.clear_entry, 'Danger.TButton'),
             ("⌫", self.backspace, 'Danger.TButton'),
             ("÷", lambda: self.set_operation('/'), 'Primary.TButton')],
            
            # Row 2
            [("7", lambda: self.append_number('7'), 'Number.TButton'),
             ("8", lambda: self.append_number('8'), 'Number.TButton'),
             ("9", lambda: self.append_number('9'), 'Number.TButton'),
             ("×", lambda: self.set_operation('*'), 'Primary.TButton')],
            
            # Row 3
            [("4", lambda: self.append_number('4'), 'Number.TButton'),
             ("5", lambda: self.append_number('5'), 'Number.TButton'),
             ("6", lambda: self.append_number('6'), 'Number.TButton'),
             ("-", lambda: self.set_operation('-'), 'Primary.TButton')],
            
            # Row 4
            [("1", lambda: self.append_number('1'), 'Number.TButton'),
             ("2", lambda: self.append_number('2'), 'Number.TButton'),
             ("3", lambda: self.append_number('3'), 'Number.TButton'),
             ("+", lambda: self.set_operation('+'), 'Primary.TButton')],
            
            # Row 5
            [("0", lambda: self.append_number('0'), 'Number.TButton'),
             (".", self.append_decimal, 'Number.TButton'),
             ("=", self.calculate, 'Success.TButton')]
        ]
        
        # Create button grid
        for row_idx, row in enumerate(buttons):
            row_frame = ttk.Frame(parent)
            row_frame.pack(fill='x', pady=2)
            
            for col_idx, (text, command, style) in enumerate(row):
                # Adjust colspan for = button
                colspan = 2 if text == "=" else 1
                
                btn = ttk.Button(row_frame,
                               text=text,
                               style=style,
                               command=command)
                btn.grid(row=0, column=col_idx, sticky='nsew', padx=2)
                
                # Make = button wider
                if text == "=":
                    btn.grid(columnspan=2, sticky='nsew')
            
            # Configure grid columns
            for i in range(4):
                row_frame.grid_columnconfigure(i, weight=1)
    
    def create_financial_functions(self, parent):
        """Create financial calculation buttons"""
        finance_frame = ttk.LabelFrame(parent, text="Financial Functions", padding=10)
        finance_frame.pack(fill='x', pady=(10, 0))
        
        finance_buttons = [
            ("Interest", self.calculate_interest),
            ("Loan Payment", self.calculate_loan),
            ("Savings Goal", self.calculate_savings),
            ("Currency", self.currency_converter)
        ]
        
        for text, command in finance_buttons:
            btn = ttk.Button(finance_frame,
                           text=text,
                           command=command)
            btn.pack(side='left', padx=2, fill='x', expand=True)
    
    def bind_events(self):
        """Bind keyboard events"""
        # Number keys
        for num in range(10):
            self.root.bind(str(num), lambda e, n=num: self.append_number(str(n)))
        
        # Operation keys
        self.root.bind('+', lambda e: self.set_operation('+'))
        self.root.bind('-', lambda e: self.set_operation('-'))
        self.root.bind('*', lambda e: self.set_operation('*'))
        self.root.bind('/', lambda e: self.set_operation('/'))
        
        # Special keys
        self.root.bind('<Return>', lambda e: self.calculate())
        self.root.bind('<Escape>', lambda e: self.clear())
        self.root.bind('<BackSpace>', lambda e: self.backspace())
        self.root.bind('.', lambda e: self.append_decimal())
        self.root.bind('c', lambda e: self.clear())
    
    def append_number(self, number):
        """Append number to current input"""
        if self.current_input == "0":
            self.current_input = number
        else:
            self.current_input += number
        
        self.update_display()
    
    def append_decimal(self):
        """Append decimal point"""
        if '.' not in self.current_input:
            self.current_input += '.'
            self.update_display()
    
    def set_operation(self, op):
        """Set operation for calculation"""
        if self.previous_value is None:
            self.previous_value = float(self.current_input)
        elif self.operation:
            self.calculate()
            self.previous_value = float(self.current_input)
        
        self.operation = op
        self.history_label.config(text=f"{self.previous_value} {op}")
        self.current_input = "0"
    
    def calculate(self):
        """Perform calculation"""
        if self.operation and self.previous_value is not None:
            current = float(self.current_input)
            
            try:
                if self.operation == '+':
                    result = self.previous_value + current
                elif self.operation == '-':
                    result = self.previous_value - current
                elif self.operation == '*':
                    result = self.previous_value * current
                elif self.operation == '/':
                    if current == 0:
                        raise ZeroDivisionError
                    result = self.previous_value / current
                
                # Update history
                calculation = f"{self.previous_value} {self.operation} {current} = {result}"
                self.history.append(calculation)
                
                # Update display
                self.current_input = str(result)
                self.history_label.config(text=calculation)
                self.update_display()
                
            except ZeroDivisionError:
                self.current_input = "Error"
                self.update_display()
            
            # Reset operation
            self.operation = None
            self.previous_value = None
    
    def clear(self):
        """Clear all"""
        self.current_input = "0"
        self.previous_value = None
        self.operation = None
        self.history_label.config(text="")
        self.update_display()
    
    def clear_entry(self):
        """Clear current entry"""
        self.current_input = "0"
        self.update_display()
    
    def backspace(self):
        """Remove last character"""
        if len(self.current_input) > 1:
            self.current_input = self.current_input[:-1]
        else:
            self.current_input = "0"
        self.update_display()
    
    def update_display(self):
        """Update display with current input"""
        # Format number with commas
        try:
            num = float(self.current_input)
            formatted = f"{num:,.2f}"
            # Remove unnecessary decimal places
            if formatted.endswith(".00"):
                formatted = formatted[:-3]
            self.display_var.set(formatted)
        except ValueError:
            self.display_var.set(self.current_input)
    
    # Memory functions
    def memory_clear(self):
        """Clear memory"""
        self.memory = 0
    
    def memory_recall(self):
        """Recall from memory"""
        self.current_input = str(self.memory)
        self.update_display()
    
    def memory_add(self):
        """Add to memory"""
        try:
            self.memory += float(self.current_input)
        except ValueError:
            pass
    
    def memory_subtract(self):
        """Subtract from memory"""
        try:
            self.memory -= float(self.current_input)
        except ValueError:
            pass
    
    def memory_store(self):
        """Store in memory"""
        try:
            self.memory = float(self.current_input)
        except ValueError:
            pass
    
