        <li>Live filtering</li>
        <li>Refreshing results</li>
    </ul>

    <hr/>

    <h3>Basic Search Query</h3>
    <div style="background-color:#e0e0e0; padding:15px;">
        <pre>
cursor.execute(
    "SELECT * FROM products WHERE name LIKE ?",
    ('%lap%',)
)
        </pre>
    </div>

    <hr/>

    <h3>Search Function</h3>
    <div style="background-color:#e0e0e0; padding:15px;">
        <pre>
def search_product():
    keyword = search_entry.get()
    cursor.execute(
        "SELECT name, price, quantity FROM products WHERE name LIKE ?",
        ('%' + keyword + '%',)
    )
    rows = cursor.fetchall()
    refresh_table(rows)
        </pre>
